#include <stdio.h>

int main() {
    int T, X;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        scanf("%d", &X);
        int buckets = (X - 100) / 50;
        if (buckets < 0) buckets = 0;
        printf("%d\n", buckets);
    }
    return 0;
}

